"use client";

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  MediaEditor01,
  type MediaEditor01Handle,
  type MediaEditor01Labels,
  type EditorCtx,
} from "../media-editor-01";
import { ComposerPublishBar } from "./parts/composer-publish-bar";
import { PublishingProgressOverlay } from "./parts/publishing-progress-overlay";
import { useImageUploader } from "./hooks/use-image-uploader";
import {
  DEFAULT_STORY_COMPOSER_LABELS,
  type ComposerCtx,
  type ComposerMode,
  type ComposerStage,
  type PublishedStory,
  type PublishMetadata,
  type StoryComposer01Handle,
  type StoryComposer01Labels,
  type StoryComposer01Props,
} from "./types";

/**
 * StoryComposer01 v0.2.0 — thin wrapper around `MediaEditor01`.
 *
 * Maps the v0.1.5 props 1:1 onto the media-editor surface, fixes
 * `aspect="9:16"` (Instagram-canonical), and overlays the story-shaped
 * publish flow (XHR upload + progress + onPublished/onPublishError).
 *
 * Public API preserved 100%: every v0.1.5 prop is accepted and every
 * v0.1.5 ref-handle method resolves. Internal orchestration that lived
 * in this file in v0.1.5 (camera, tool panels, discard guard, history,
 * text-only canvas) now lives inside MediaEditor01 — landed in the R1–R4
 * backfill commits.
 *
 * Known v0.2.0 polish gaps (none break the type contract):
 *   - `labels` overrides pass through verbatim as the v0.1.5 flat shape;
 *     full MediaEditor01Labels nested-shape mapping lands at C17.
 *   - `editorBackground` prop is accepted but not forwarded — the
 *     editor canvas always uses "#000" (matches the v0.1.5 default).
 *     Re-exposed in v0.2.1 if needed.
 *   - `renderPublishingOverlay` is a no-op slot in v0.2.0; the default
 *     `PublishingProgressOverlay` renders during publish.
 */

const ALL_MODES: ComposerMode[] = ["photo", "video", "text"];

type PublishStatus = "idle" | "compositing" | "uploading" | "done" | "error";

export const StoryComposer01 = forwardRef<
  StoryComposer01Handle,
  StoryComposer01Props
>(function StoryComposer01(props, ref) {
  const {
    isOpen,
    onClose,
    defaultMode,
    hideModes,
    defaultFacing,
    recordAudio,
    maxFileSizeMb,
    maxVideoDuration,
    presentation = "auto",
    confirmOnDiscard = true,
    enabledTools = ["text", "draw", "stickers", "filters", "adjust"],
    stickers,
    replaceBuiltinStickers,
    filterPresets,
    replaceBuiltinFilters,
    cropAspects,
    fonts,
    colorPresets,
    labels: labelOverrides,
    onValidationError,
    onPermissionDenied,
    renderTopBar,
    renderBottomToolbar,
    renderEmpty,
    renderPermissionDenied,
    uploadUrl,
    uploader,
    uploadFields,
    onPublished,
    onPublishError,
  } = props;

  const editorRef = useRef<MediaEditor01Handle>(null);

  // hideModes (subtract) → enabledModes (positive). Empty hideModes ⇒ all
  // three modes enabled, matching the v0.1.5 default.
  const enabledModes = useMemo<ComposerMode[]>(
    () => ALL_MODES.filter((m) => !hideModes?.includes(m)),
    [hideModes],
  );

  // story-composer's `presentation` enum vs media-editor's. "fullscreen" and
  // "modal" both map to "dialog" since media-editor's dialog mode is
  // mobile-fullscreen + desktop-modal. "auto" passes through.
  const editorPresentation = useMemo<"inline" | "dialog" | "auto">(() => {
    if (presentation === "fullscreen" || presentation === "modal") {
      return "dialog";
    }
    return "auto";
  }, [presentation]);

  const labels = useMemo<Required<StoryComposer01Labels>>(
    () => ({ ...DEFAULT_STORY_COMPOSER_LABELS, ...labelOverrides }),
    [labelOverrides],
  );

  const uploader_ = useImageUploader({ uploadUrl, uploader, uploadFields });

  const [publishStatus, setPublishStatus] = useState<PublishStatus>("idle");
  const [uploadProgress, setUploadProgress] = useState(0);

  // Mirror uploader_.progress (0..1) into uploadProgress's upload half
  // (0.5..1) so the progress bar advances smoothly through the upload phase
  // instead of jumping from 0.5 to 1.
  useEffect(() => {
    if (publishStatus !== "uploading") return;
    setUploadProgress(0.5 + uploader_.progress * 0.5);
  }, [publishStatus, uploader_.progress]);

  const handlePublish = useCallback(async () => {
    if (!editorRef.current) return;
    try {
      setPublishStatus("compositing");
      setUploadProgress(0);
      const { blob, metadata } = await editorRef.current.export({
        // Export takes the first half of the progress bar; upload the second.
        onProgress: (p) => setUploadProgress(p * 0.5),
      });
      // ExportMetadata → PublishMetadata (drop the editor-only `crop` field).
      const publishMeta: PublishMetadata = {
        mode: metadata.mode,
        width: metadata.width,
        height: metadata.height,
        durationMs: metadata.durationMs,
        mimeType: metadata.mimeType,
        textOverlays: metadata.textOverlays,
        stickers: metadata.stickers,
        drawingStrokes: metadata.drawingStrokes,
        appliedFilter: metadata.appliedFilter,
        adjustments: metadata.adjustments,
      };
      setPublishStatus("uploading");
      // Upload runs the second half of the bar; uploader_.progress is mirrored
      // into uploadProgress via the effect below.
      const result = await uploader_.upload(blob, publishMeta);
      setUploadProgress(1);

      const story: PublishedStory = {
        id: `story-${Date.now()}`,
        createdAt: new Date().toISOString(),
        items: [
          {
            id: `item-${Date.now()}`,
            type: metadata.mode === "video" ? "video" : "image",
            src: result.url,
            duration:
              metadata.mode === "video"
                ? Math.round((metadata.durationMs ?? 0) / 1000) || undefined
                : undefined,
            thumbnailUrl: result.thumbnailUrl,
          },
        ],
      };
      setPublishStatus("done");
      onPublished(story);
    } catch (err) {
      setPublishStatus("error");
      const e = err instanceof Error ? err : new Error(String(err));
      onPublishError?.(e);
    }
  }, [uploader_, onPublished, onPublishError]);

  // EditorCtx → ComposerCtx translation for slot consumers. story-composer's
  // ctx assumes a non-null mode + has publishing/cancel/publish helpers.
  const toComposerCtx = useCallback(
    (ctx: EditorCtx): ComposerCtx => ({
      mode: ctx.mode ?? "photo",
      stage: ctx.stage as ComposerStage,
      isDirty: ctx.isDirty,
      publishing: {
        active:
          publishStatus === "compositing" || publishStatus === "uploading",
        progress: uploadProgress,
      },
      setMode: (m) => {
        // No public setter on the handle; delegate via the editor ref's
        // internal state surface in v0.2.0. v0.3.0 may expose setMode().
        editorRef.current?.loadState({
          ...(editorRef.current.getState() ?? {}),
          mode: m,
        } as ReturnType<NonNullable<typeof editorRef.current>["getState"]>);
      },
      cancel: () => onClose(),
      publish: handlePublish,
    }),
    [publishStatus, uploadProgress, handlePublish, onClose],
  );

  useImperativeHandle(
    ref,
    (): StoryComposer01Handle => ({
      open: () => editorRef.current?.open(),
      close: () => editorRef.current?.close(),
      reset: () => {
        editorRef.current?.reset();
        setPublishStatus("idle");
        setUploadProgress(0);
      },
      switchCamera: async () => {
        await editorRef.current?.switchCamera();
      },
      takePhoto: async () => {
        await editorRef.current?.takePhoto();
      },
      startRecording: async () => {
        await editorRef.current?.startRecording();
      },
      stopRecording: async () => {
        await editorRef.current?.stopRecording();
      },
      importFromGallery: () => editorRef.current?.importFromGallery(),
      addText: (text) => editorRef.current?.addText(text),
      addSticker: (sticker) => editorRef.current?.addSticker(sticker),
      setAdjustments: (adj) => editorRef.current?.setAdjustments(adj),
      applyFilter: (name) => editorRef.current?.applyFilter(name),
      publish: handlePublish,
      exportBlob: async () => {
        if (!editorRef.current) {
          throw new Error("story-composer-01: editor not mounted");
        }
        const out = await editorRef.current.export();
        const publishMeta: PublishMetadata = {
          mode: out.metadata.mode,
          width: out.metadata.width,
          height: out.metadata.height,
          durationMs: out.metadata.durationMs,
          mimeType: out.metadata.mimeType,
          textOverlays: out.metadata.textOverlays,
          stickers: out.metadata.stickers,
          drawingStrokes: out.metadata.drawingStrokes,
          appliedFilter: out.metadata.appliedFilter,
          adjustments: out.metadata.adjustments,
        };
        return { blob: out.blob, metadata: publishMeta };
      },
    }),
    [handlePublish],
  );

  return (
    <>
      <MediaEditor01
        ref={editorRef}
        aspect="9:16"
        enabledModes={enabledModes}
        enabledTools={enabledTools}
        mediaSources={["camera", "upload"]}
        presentation={editorPresentation}
        isOpen={isOpen}
        onClose={onClose}
        confirmOnDiscard={confirmOnDiscard}
        defaultMode={defaultMode}
        defaultFacing={defaultFacing}
        recordAudio={recordAudio}
        maxFileSizeMb={maxFileSizeMb}
        maxVideoDuration={maxVideoDuration}
        stickers={stickers}
        replaceBuiltinStickers={replaceBuiltinStickers}
        filterPresets={filterPresets}
        replaceBuiltinFilters={replaceBuiltinFilters}
        cropAspects={cropAspects}
        fonts={fonts}
        colorPresets={colorPresets}
        // Pass-through of label overrides — MediaEditor accepts as flat shape
        // via INTERNAL_LABELS_FALLBACK merge (R2). C17 will refactor onto
        // the nested MediaEditor01Labels surface.
        labels={labelOverrides as unknown as Partial<MediaEditor01Labels>}
        onValidationError={onValidationError}
        onPermissionDenied={onPermissionDenied}
        renderEmpty={renderEmpty}
        renderPermissionDenied={renderPermissionDenied}
        renderTopBar={(ctx) =>
          renderTopBar ? (
            renderTopBar(toComposerCtx(ctx))
          ) : (
            <ComposerPublishBar
              isPublishing={
                publishStatus === "compositing" ||
                publishStatus === "uploading"
              }
              canPublish={ctx.isDirty}
              labels={labels}
              onPublish={handlePublish}
              onClose={onClose}
            />
          )
        }
        renderBottomToolbar={
          renderBottomToolbar
            ? (ctx) => renderBottomToolbar(toComposerCtx(ctx))
            : undefined
        }
      />
      {publishStatus === "uploading" ||
      publishStatus === "compositing" ||
      publishStatus === "error" ? (
        <PublishingProgressOverlay
          progress={publishStatus === "uploading" ? uploadProgress : null}
          status={publishStatus === "error" ? "error" : "uploading"}
          labels={labels}
          onRetry={publishStatus === "error" ? handlePublish : undefined}
          onCancel={() => {
            uploader_.cancel();
            setPublishStatus("idle");
            setUploadProgress(0);
          }}
        />
      ) : null}
    </>
  );
});

// ─── Main component ────────────────────────────────────────────────────

export { StoryComposer01 } from "./story-composer-01";

// ─── Types ─────────────────────────────────────────────────────────────

export type {
  StoryComposer01Props,
  StoryComposer01Handle,
  StoryComposer01Labels,
  ComposerMode,
  ComposerStage,
  ComposerCtx,
  ValidationError,
  StickerOption,
  StickerSet,
  FontOption,
  FilterPreset,
  KonvaFilterSpec,
  ImageAdjustments,
  TextOverlay,
  PlacedSticker,
  DrawingStroke,
  AspectRatio,
  EditTool,
  PublishMetadata,
  PublishResult,
  PublishedStory,
  PublishedStoryItem,
  Uploader,
} from "./types";

export {
  DEFAULT_STORY_COMPOSER_LABELS,
  DEFAULT_ADJUSTMENTS,
} from "./types";

// ─── Exported sealed-folder parts ──────────────────────────────────────

// ComposerPublishBar STAYS in story-composer-01 (story-shaped publish UI).
export { ComposerPublishBar } from "./parts/composer-publish-bar";
export type { ComposerPublishBarProps } from "./parts/composer-publish-bar";

// 3 parts moved + renamed in v0.2.0; backward-compat aliases preserve v0.1.5 names.
// @deprecated import EditorCamera/EditorCanvas/EditorToolbar from "@ilinxa/media-editor-01".
export {
  EditorCamera as ComposerCamera,
  EditorCanvas as ComposerEditor,
  EditorToolbar as ComposerToolbar,
  ColorSwatchPicker,
} from "../media-editor-01";

// Props types for the renamed parts — also re-exported under old names.
export type {
  EditorCameraProps as ComposerCameraProps,
  EditorCanvasProps as ComposerEditorProps,
  EditorToolbarProps as ComposerToolbarProps,
  ColorSwatchPickerProps,
} from "../media-editor-01";

// ─── Exported hooks (plan §10) ─────────────────────────────────────────

export {
  useStoryComposerState,
  type UseStoryComposerStateOptions,
  type UseStoryComposerStateResult,
} from "./hooks/use-story-composer-state";

// Re-exports — useMediaCapture + utilities moved to media-editor-01 in v0.2.0.
// Preserved here for v0.1.5 consumer backward-compat per snapshot contract.
/** @deprecated v0.2.0 — import from `@ilinxa/media-editor-01` directly. Removed in v0.3.0. */
export {
  useMediaCapture,
  validateGalleryFile,
  suggestedVideoFilename,
  type UseMediaCaptureOptions,
  type UseMediaCaptureResult,
  type CapturedPhoto,
  type CapturedVideo,
  type CaptureStatus,
  type FacingMode,
} from "../media-editor-01";

export {
  useImageUploader,
  type UseImageUploaderOptions,
  type UseImageUploaderResult,
  type UploadStatus,
} from "./hooks/use-image-uploader";

// ─── Lib helpers ───────────────────────────────────────────────────────
// All lib helpers moved to media-editor-01 in v0.2.0.
// @deprecated import from "@ilinxa/media-editor-01" — removed in v0.3.0.

export {
  resolveFilterPresets,
  BUILT_IN_FILTER_PRESETS,
  resolveStickerSets,
  BUILT_IN_STICKER_SETS,
  exportPhotoBlob,
  exportTextOnlyBlob,
  type ExportPhotoOptions,
  compositeVideo,
  type CompositeVideoOptions,
  type CompositeVideoResult,
  selectRecorderMime,
  containerFor,
  PREFERRED_RECORDER_MIME_TYPES,
  type RecorderMimeType,
} from "../media-editor-01";

// ─── Default tokens ────────────────────────────────────────────────────
// Moved to media-editor-01/lib/defaults.ts in v0.2.0.
// @deprecated import from "@ilinxa/media-editor-01" — removed in v0.3.0.

export {
  DEFAULT_TEXT_GRADIENTS,
  DEFAULT_FONTS,
  DEFAULT_COLOR_PRESETS,
  type GradientPreset,
} from "../media-editor-01";

// ─── Crop helpers (CropRect type lives here; helper functions too) ─────

// Crop helpers moved with tool-crop-overlay to media-editor-01 in v0.2.0.
// @deprecated import from "@ilinxa/media-editor-01" — removed in v0.3.0.
export {
  fitCropToStage,
  ASPECT_RATIO_VALUES,
  type CropRect,
} from "../media-editor-01";

import type { ReactNode } from "react";
import type { AspectRatio } from "../media-editor-01";
export type { AspectRatio };

// ─── Modes + stage ──────────────────────────────────────────────────────

export type ComposerMode = "photo" | "video" | "text";

export type ComposerStage =
  | "capture"
  | "edit"
  | "publishing"
  | "done"
  | "error";

// ─── Validation ─────────────────────────────────────────────────────────

export interface ValidationError {
  kind:
    | "file-too-large"
    | "unsupported-type"
    | "unsupported-codec"
    | "duration-exceeded"
    | "no-camera"
    | "permission-denied";
  message: string;
  file?: File;
}

// ─── Stickers ───────────────────────────────────────────────────────────

export interface StickerOption {
  id: string;
  src: string;
  alt: string;
  width?: number;
  height?: number;
}

export interface StickerSet {
  id: string;
  label: string;
  stickers: StickerOption[];
}

// ─── Filters + adjustments ──────────────────────────────────────────────

export interface KonvaFilterSpec {
  name: string;
  params?: Record<string, number>;
}

export interface FilterPreset {
  id: string;
  label: string;
  konvaFilters: KonvaFilterSpec[];
}

export interface ImageAdjustments {
  brightness: number;
  contrast: number;
  saturation: number;
  blur: number;
}

export const DEFAULT_ADJUSTMENTS: ImageAdjustments = {
  brightness: 0,
  contrast: 0,
  saturation: 0,
  blur: 0,
};

// ─── Overlay items ──────────────────────────────────────────────────────

export interface TextOverlay {
  id: string;
  text: string;
  x: number;
  y: number;
  rotation: number;
  scale: number;
  fontFamily: string;
  fontSize: number;
  fill: string;
  align: "left" | "center" | "right";
}

export interface PlacedSticker {
  id: string;
  stickerId: string;
  x: number;
  y: number;
  rotation: number;
  scale: number;
}

export interface DrawingStroke {
  id: string;
  points: number[];
  color: string;
  brushSize: number;
  mode: "draw" | "erase";
}

// ─── Fonts ──────────────────────────────────────────────────────────────

export interface FontOption {
  id: string;
  label: string;
  family: string;
}

// ─── Aspect ratios + tools ──────────────────────────────────────────────

// AspectRatio moved to media-editor-01 in v0.2.0 (added "16:9" as additive
// non-breaking extension — narrowing-style consumers unaffected).
// Imported here so this types.ts can reference AspectRatio internally + re-exports it.

export type EditTool =
  | "text"
  | "draw"
  | "stickers"
  | "filters"
  | "adjust"
  | "crop";

// ─── Publish ────────────────────────────────────────────────────────────

export interface PublishMetadata {
  mode: ComposerMode;
  width: number;
  height: number;
  durationMs?: number;
  mimeType: string;
  textOverlays: TextOverlay[];
  stickers: PlacedSticker[];
  drawingStrokes: number;
  appliedFilter?: string;
  adjustments: ImageAdjustments;
}

export interface PublishResult {
  url: string;
  thumbnailUrl?: string;
  [key: string]: unknown;
}

export interface PublishedStoryItem {
  id: string;
  type: "image" | "video";
  src: string;
  duration?: number;
  thumbnailUrl?: string;
}

export interface PublishedStory {
  id: string;
  createdAt: string;
  items: PublishedStoryItem[];
}

// ─── Slot context ───────────────────────────────────────────────────────

export interface ComposerCtx {
  mode: ComposerMode;
  stage: ComposerStage;
  isDirty: boolean;
  publishing: { active: boolean; progress: number };
  setMode: (m: ComposerMode) => void;
  cancel: () => void;
  publish: () => Promise<void>;
}

// ─── Uploader ───────────────────────────────────────────────────────────

export type Uploader = (
  blob: Blob,
  metadata: PublishMetadata,
) => Promise<PublishResult>;

// ─── i18n labels ────────────────────────────────────────────────────────

export interface StoryComposer01Labels {
  composerLabel?: string;
  composerDescription?: string;

  modePhoto?: string;
  modeVideo?: string;
  modeText?: string;

  shutterPhoto?: string;
  shutterVideoStart?: string;
  shutterVideoStop?: string;

  galleryPicker?: string;
  switchCamera?: string;

  permissionDeniedTitle?: string;
  permissionDeniedBody?: string;
  permissionRetry?: string;
  permissionUsePicker?: string;
  permissionRequesting?: string;

  toolText?: string;
  toolDraw?: string;
  toolStickers?: string;
  toolFilters?: string;
  toolAdjust?: string;
  toolCrop?: string;

  adjustBrightness?: string;
  adjustContrast?: string;
  adjustSaturation?: string;
  adjustBlur?: string;

  drawColor?: string;
  drawBrush?: string;
  drawEraser?: string;
  drawUndo?: string;
  drawRedo?: string;

  textPlaceholder?: string;
  textFontFamily?: string;
  textFontSize?: string;
  textAlign?: string;

  publish?: string;
  publishing?: string;
  published?: string;
  close?: string;

  discardConfirmTitle?: string;
  discardConfirmBody?: string;
  discardConfirm?: string;
  discardCancel?: string;

  uploadFailedTitle?: string;
  uploadRetry?: string;

  recordingLabel?: string;
  trimStart?: string;
  trimEnd?: string;
}

export const DEFAULT_STORY_COMPOSER_LABELS: Required<StoryComposer01Labels> = {
  composerLabel: "Create story",
  composerDescription:
    "Create a new story by capturing a photo, recording a video, or composing a text-only message. Tap the close button to exit.",

  modePhoto: "Photo",
  modeVideo: "Video",
  modeText: "Text",

  shutterPhoto: "Take photo",
  shutterVideoStart: "Start recording",
  shutterVideoStop: "Stop recording",

  galleryPicker: "Choose from gallery",
  switchCamera: "Switch camera",

  permissionDeniedTitle: "Camera access blocked",
  permissionDeniedBody:
    "We need camera permission to capture your story. Enable it in your browser settings, or choose a file from your gallery.",
  permissionRetry: "Try again",
  permissionUsePicker: "Use gallery instead",
  permissionRequesting: "Requesting camera…",

  toolText: "Text",
  toolDraw: "Draw",
  toolStickers: "Stickers",
  toolFilters: "Filters",
  toolAdjust: "Adjust",
  toolCrop: "Crop",

  adjustBrightness: "Brightness",
  adjustContrast: "Contrast",
  adjustSaturation: "Saturation",
  adjustBlur: "Blur",

  drawColor: "Color",
  drawBrush: "Brush size",
  drawEraser: "Eraser",
  drawUndo: "Undo",
  drawRedo: "Redo",

  textPlaceholder: "Type something…",
  textFontFamily: "Font",
  textFontSize: "Size",
  textAlign: "Align",

  publish: "Publish",
  publishing: "Publishing…",
  published: "Published",
  close: "Close",

  discardConfirmTitle: "Discard story?",
  discardConfirmBody:
    "You'll lose your captured media and edits. This can't be undone.",
  discardConfirm: "Discard",
  discardCancel: "Keep editing",

  uploadFailedTitle: "Upload failed",
  uploadRetry: "Try again",

  recordingLabel: "Recording",
  trimStart: "Start",
  trimEnd: "End",
};

// ─── Public component props ─────────────────────────────────────────────

export interface StoryComposer01Props {
  // Display
  isOpen: boolean;
  onClose: () => void;

  // Publish destination
  uploadUrl?: string;
  uploader?: Uploader;
  uploadFields?: Record<string, string>;
  onPublished: (story: PublishedStory) => void;
  onPublishError?: (error: Error) => void;

  // Capture
  defaultMode?: ComposerMode;
  hideModes?: ComposerMode[];
  defaultFacing?: "user" | "environment";
  maxVideoDuration?: number;
  recordAudio?: boolean;
  maxFileSizeMb?: number;
  onValidationError?: (error: ValidationError) => void;

  // Edit tools
  stickers?: StickerSet[];
  replaceBuiltinStickers?: boolean;
  fonts?: FontOption[];
  colorPresets?: string[];
  filterPresets?: FilterPreset[];
  replaceBuiltinFilters?: boolean;
  enabledTools?: EditTool[];

  // Layout + behavior
  cropAspects?: AspectRatio[];
  presentation?: "auto" | "fullscreen" | "modal";
  editorBackground?: string;
  confirmOnDiscard?: boolean;

  // Localization
  labels?: Partial<StoryComposer01Labels>;

  // Permissions
  onPermissionDenied?: () => void;

  // Slots
  renderTopBar?: (ctx: ComposerCtx) => ReactNode;
  renderBottomToolbar?: (ctx: ComposerCtx) => ReactNode;
  renderPermissionDenied?: (ctx: {
    retry: () => void;
    usePicker: () => void;
  }) => ReactNode;
  renderEmpty?: () => ReactNode;
  renderPublishingOverlay?: (ctx: {
    progress: number;
    mode: ComposerMode;
  }) => ReactNode;
}

// ─── Imperative handle ──────────────────────────────────────────────────

export interface StoryComposer01Handle {
  // Lifecycle
  open: () => void;
  close: () => void;
  reset: () => void;
  // Capture
  switchCamera: () => Promise<void>;
  takePhoto: () => Promise<void>;
  startRecording: () => Promise<void>;
  stopRecording: () => Promise<void>;
  importFromGallery: () => void;
  // Edit
  addText: (text?: string) => void;
  addSticker: (sticker: StickerOption) => void;
  setAdjustments: (adj: Partial<ImageAdjustments>) => void;
  applyFilter: (name: string | null) => void;
  // Publish
  publish: () => Promise<void>;
  exportBlob: () => Promise<{ blob: Blob; metadata: PublishMetadata }>;
}

"use client";

import { useCallback, useRef, useState } from "react";
import type {
  PublishMetadata,
  PublishResult,
  Uploader,
} from "../types";

export type UploadStatus =
  | "idle"
  | "uploading"
  | "done"
  | "error"
  | "cancelled";

export interface UseImageUploaderOptions {
  /** Server endpoint for default POST FormData upload (Q-P6a). */
  uploadUrl?: string;
  /** Extra FormData fields appended to every request. */
  uploadFields?: Record<string, string>;
  /** Custom uploader — wins over uploadUrl when both are set. */
  uploader?: Uploader;
}

export interface UseImageUploaderResult {
  status: UploadStatus;
  /** 0..1 — determinate when XMLHttpRequest reports lengthComputable. */
  progress: number;
  error: Error | null;
  upload: (blob: Blob, metadata: PublishMetadata) => Promise<PublishResult>;
  cancel: () => void;
  reset: () => void;
}

/**
 * Default POST FormData uploader (Q-P6a) + escape hatch for signed-URL flows.
 *
 * XMLHttpRequest, not fetch — fetch lacks upload-progress events in browsers,
 * which the publishing overlay needs for a determinate progress bar.
 */
export function useImageUploader(
  options: UseImageUploaderOptions,
): UseImageUploaderResult {
  const { uploadUrl, uploadFields, uploader } = options;
  const [status, setStatus] = useState<UploadStatus>("idle");
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<Error | null>(null);
  const xhrRef = useRef<XMLHttpRequest | null>(null);

  const reset = useCallback(() => {
    setStatus("idle");
    setProgress(0);
    setError(null);
  }, []);

  const cancel = useCallback(() => {
    xhrRef.current?.abort();
    xhrRef.current = null;
    setStatus("cancelled");
  }, []);

  const upload = useCallback(
    async (blob: Blob, metadata: PublishMetadata): Promise<PublishResult> => {
      setStatus("uploading");
      setProgress(0);
      setError(null);

      // Custom uploader path (S3 pre-signed PUT / Cloudinary / Mux).
      if (uploader) {
        try {
          const result = await uploader(blob, metadata);
          setStatus("done");
          setProgress(1);
          return result;
        } catch (err) {
          const e = err as Error;
          setStatus("error");
          setError(e);
          throw e;
        }
      }

      // Default POST FormData path.
      if (!uploadUrl) {
        const e = new Error(
          "story-composer-01: pass `uploadUrl` or `uploader` to publish.",
        );
        setStatus("error");
        setError(e);
        throw e;
      }

      return new Promise<PublishResult>((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhrRef.current = xhr;
        xhr.open("POST", uploadUrl, true);

        xhr.upload.onprogress = (ev) => {
          if (ev.lengthComputable) {
            setProgress(ev.loaded / ev.total);
          }
        };

        xhr.onload = () => {
          xhrRef.current = null;
          if (xhr.status >= 200 && xhr.status < 300) {
            try {
              const text = xhr.responseText;
              const parsed: PublishResult = text
                ? JSON.parse(text)
                : { url: "" };
              if (!parsed.url) {
                // Allow servers that return 200 without a body, but caller
                // probably wants the URL — leave it blank and proceed.
                parsed.url = "";
              }
              setStatus("done");
              setProgress(1);
              resolve(parsed);
            } catch (parseErr) {
              const e =
                parseErr instanceof Error
                  ? parseErr
                  : new Error("Upload response was not JSON");
              setStatus("error");
              setError(e);
              reject(e);
            }
          } else {
            const e = new Error(`Upload failed (HTTP ${xhr.status})`);
            setStatus("error");
            setError(e);
            reject(e);
          }
        };

        xhr.onerror = () => {
          xhrRef.current = null;
          const e = new Error("Upload network error");
          setStatus("error");
          setError(e);
          reject(e);
        };

        xhr.onabort = () => {
          xhrRef.current = null;
          // status already set to "cancelled" by cancel()
        };

        const form = new FormData();
        const ext = blob.type.includes("webm")
          ? "webm"
          : blob.type.includes("mp4")
            ? "mp4"
            : blob.type.includes("png")
              ? "png"
              : "jpg";
        form.append(
          "file",
          blob,
          `story-${Date.now()}.${ext}`,
        );
        // Append metadata as a JSON string so backends can pick keys they want.
        form.append("metadata", JSON.stringify(metadata));
        if (uploadFields) {
          for (const [k, v] of Object.entries(uploadFields)) form.append(k, v);
        }
        xhr.send(form);
      });
    },
    [uploadFields, uploadUrl, uploader],
  );

  return { status, progress, error, upload, cancel, reset };
}

