import type { ReactNode } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogTitle,
} from "@/components/ui/dialog";
import { cn } from "@/lib/utils";

export interface ComposerShellProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  /** "auto" picks fullscreen <md, modal >=md. */
  presentation?: "auto" | "fullscreen" | "modal";
  /** Hex/CSS color for the canvas surface. Default near-black. */
  background?: string;
  /** Accessible label, fed into a visually-hidden DialogTitle. */
  ariaLabel: string;
  /** Accessible description, fed into a visually-hidden DialogDescription.
   * Radix logs a warning when DialogContent has no Description child + no
   * aria-describedby. Default is generic — override via Story composer's
   * labels.composerDescription. */
  ariaDescription: string;
  children: ReactNode;
}

/**
 * Mobile-fullscreen / desktop-modal Dialog wrapper.
 *
 * Overrides shadcn's default `sm:max-w-sm` + padding + rounded-xl with `!`-suffixed
 * utilities (the v0.4.1 story-viewer-01 mobile-fullscreen fix pattern) so the
 * composer is full-bleed on mobile and a true 9:16 portrait modal on desktop.
 */
export function ComposerShell({
  isOpen,
  onOpenChange,
  presentation = "auto",
  background = "#000",
  ariaLabel,
  ariaDescription,
  children,
}: ComposerShellProps) {
  const isFullscreenAlways = presentation === "fullscreen";
  const isModalAlways = presentation === "modal";

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent
        // Beat shadcn's `sm:max-w-sm` + p-4 + gap-4 + rounded-xl + bg-popover with `!`.
        // The `[&_[data-slot=dialog-close]]:hidden` selector hides shadcn's
        // built-in close button — composer owns its own close in the publish
        // bar. Inlined here (vs. `showCloseButton={false}`) because that prop
        // is producer-side-only; older consumer dialog.tsx versions don't
        // ship it. CSS-hide works against any shadcn dialog version.
        className={cn(
          // Reset
          "!gap-0 !p-0 !bg-transparent !ring-0 [&_[data-slot=dialog-close]]:hidden",
          // Sizing
          isFullscreenAlways
            ? "!fixed !inset-0 !top-0 !left-0 !w-screen !h-[100dvh] !translate-x-0 !translate-y-0 !max-w-none !rounded-none"
            : isModalAlways
              ? "!w-100 !h-[44.4375rem] !max-w-none !rounded-2xl !overflow-hidden"
              : // "auto": full-screen <md, 400×711 9:16 modal >=md
                "!fixed !inset-0 !top-0 !left-0 !w-screen !h-[100dvh] !translate-x-0 !translate-y-0 !max-w-none !rounded-none md:!fixed md:!inset-auto md:!top-1/2 md:!left-1/2 md:!w-100 md:!h-[44.4375rem] md:!-translate-x-1/2 md:!-translate-y-1/2 md:!rounded-2xl md:!overflow-hidden",
          // Content surface
          "flex flex-col text-white",
        )}
        style={{ background }}
      >
        <DialogTitle className="sr-only">{ariaLabel}</DialogTitle>
        <DialogDescription className="sr-only">
          {ariaDescription}
        </DialogDescription>
        {children}
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { AlertTriangle, Check, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { StoryComposer01Labels } from "../types";

export interface PublishingProgressOverlayProps {
  /** 0..1 — null when indeterminate (no length-computable from server). */
  progress: number | null;
  status: "uploading" | "done" | "error";
  errorMessage?: string;
  labels: Required<StoryComposer01Labels>;
  onRetry?: () => void;
  onCancel?: () => void;
  className?: string;
}

export function PublishingProgressOverlay({
  progress,
  status,
  errorMessage,
  labels,
  onRetry,
  onCancel,
  className,
}: PublishingProgressOverlayProps) {
  return (
    <div
      role="status"
      aria-live="polite"
      className={cn(
        "absolute inset-0 z-40 grid place-items-center bg-black/85 backdrop-blur-sm text-white px-6",
        className,
      )}
    >
      <div className="flex flex-col items-center gap-4 text-center max-w-xs">
        {status === "uploading" ? (
          <>
            <Loader2 className="size-10 animate-spin text-white/80" />
            <p className="text-base font-medium">{labels.publishing}</p>
            {progress !== null ? (
              <div className="w-full">
                <div className="h-1.5 w-full rounded-full bg-white/15 overflow-hidden">
                  <div
                    className="h-full bg-white transition-[width] duration-150"
                    style={{ width: `${Math.round(progress * 100)}%` }}
                  />
                </div>
                <p className="mt-2 text-xs font-mono tabular-nums text-white/60">
                  {Math.round(progress * 100)}%
                </p>
              </div>
            ) : null}
            {onCancel ? (
              <Button
                variant="ghost"
                onClick={onCancel}
                className="text-white/70 hover:bg-white/10 hover:text-white"
              >
                {labels.discardCancel /* reuses "Keep editing" copy */}
              </Button>
            ) : null}
          </>
        ) : status === "done" ? (
          <>
            <div className="grid place-items-center size-12 rounded-full bg-emerald-500 text-white">
              <Check className="size-7" />
            </div>
            <p className="text-base font-medium">{labels.published}</p>
          </>
        ) : (
          <>
            <AlertTriangle className="size-10 text-amber-400" />
            <p className="text-base font-medium">{labels.uploadFailedTitle}</p>
            {errorMessage ? (
              <p className="text-xs text-white/60 leading-relaxed">
                {errorMessage}
              </p>
            ) : null}
            {onRetry ? (
              <Button
                onClick={onRetry}
                className="bg-white text-black hover:bg-white/90"
              >
                {labels.uploadRetry}
              </Button>
            ) : null}
          </>
        )}
      </div>
    </div>
  );
}
